import React, { useState, useEffect, useMemo } from 'react';
import { Icon, Modal } from './UI';
import { Clause } from '../types';
import { copyToClipboard } from '../utils';

interface ReferenceClauseModalProps {
    isOpen: boolean;
    onClose: () => void;
    clause: Clause | null;
    standardName: string;
    fullText: { en: string; vi: string };
    isLoading: boolean;
}

const ReferenceClauseModal = ({ isOpen, onClose, clause, standardName, fullText, isLoading }: ReferenceClauseModalProps) => {
    const [lang, setLang] = useState<'en' | 'vi'>('en');
    const [isCopied, setIsCopied] = useState(false);
    const [streamedText, setStreamedText] = useState("");

    const textToDisplay = lang === 'en' ? fullText.en : fullText.vi;

    // Logic to derive badge style similar to App.tsx
    const badgeData = useMemo(() => {
        if (!standardName) return { text: "ISO", colorClass: "bg-gray-100 text-gray-600" };

        const match = standardName.match(/\((.*?)\)/);
        const shortName = match ? match[1] : (standardName.split(' ')[0] || 'ISO');
        const textUpper = shortName.toUpperCase();

        let colorClass = "bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-300 border-indigo-100 dark:border-indigo-800/50";
        if (textUpper.includes('EMS') || textUpper.includes('14001')) colorClass = "bg-emerald-100 dark:bg-emerald-900/40 text-emerald-700 dark:text-emerald-300 border-emerald-200 dark:border-emerald-700/50";
        else if (textUpper.includes('QMS') || textUpper.includes('9001')) colorClass = "bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300 border-blue-200 dark:border-blue-700/50";
        else if (textUpper.includes('ISMS') || textUpper.includes('27001')) colorClass = "bg-purple-100 dark:bg-purple-900/40 text-purple-700 dark:text-purple-300 border-purple-200 dark:border-purple-700/50";

        return { text: shortName, colorClass };
    }, [standardName]);

    useEffect(() => {
        if (!isOpen) { 
            setStreamedText("");
            return;
        }

        if (isLoading || !textToDisplay) {
            setStreamedText(""); 
            return;
        }

        // Split by explicit newline for cleaner streaming effect
        const lines = textToDisplay.split('\n');
        let currentIndex = 0;
        let currentText = "";

        const startTimeout = setTimeout(() => {
            const interval = setInterval(() => {
                if (currentIndex < lines.length) {
                    // Re-append the newline that was removed by split
                    currentText += (lines[currentIndex] || '') + '\n';
                    setStreamedText(currentText);
                    currentIndex++;
                } else {
                    clearInterval(interval);
                }
            }, 20); // Faster streaming for better UX

            return () => clearInterval(interval);
        }, 50);

        return () => clearTimeout(startTimeout);
    }, [isOpen, textToDisplay, isLoading]);

    const handleCopy = () => {
        copyToClipboard(textToDisplay);
        setIsCopied(true);
        setTimeout(() => setIsCopied(false), 2000);
    };

    return (
        <Modal isOpen={isOpen} title="Clause Reference" onClose={onClose}>
            <div className="flex flex-col h-full gap-3">
                {/* Header: Title & Code */}
                {clause && (
                    <div className="flex items-start gap-3 pb-3 border-b border-gray-100 dark:border-slate-800">
                         <span className="text-base font-black text-indigo-700 dark:text-indigo-400 uppercase bg-indigo-50 dark:bg-indigo-900/30 px-3 py-1.5 rounded-lg border border-indigo-100 dark:border-indigo-800 shrink-0">{clause.code}</span>
                         <h4 className="text-base md:text-lg font-bold text-slate-800 dark:text-white leading-snug mt-0.5">{clause.title}</h4>
                    </div>
                )}

                {isLoading ? (
                    <div className="h-64 flex flex-col items-center justify-center text-slate-500 gap-4">
                        <div className="relative w-16 h-16">
                            <div className="absolute inset-0 border-2 border-indigo-200 dark:border-indigo-800 rounded-full opacity-20"></div>
                            <div className="absolute inset-0 border-t-2 border-indigo-600 rounded-full animate-spin"></div>
                        </div>
                        <span className="text-sm font-bold animate-pulse">Consulting Gemini AI Auditor...</span>
                    </div>
                ) : (
                    <>
                        {/* Compact Toolbar: Badge | Language | Actions */}
                        <div className="flex flex-wrap items-center justify-between gap-2">
                            <div className="flex items-center gap-2">
                                {/* Standard Badge */}
                                <span className={`text-[10px] font-bold px-2 py-1 rounded-full border shadow-sm uppercase tracking-wider ${badgeData.colorClass}`}>
                                    {badgeData.text}
                                </span>

                                {/* Compact Language Toggle */}
                                <div className="lang-pill-container shadow-sm border-gray-200 dark:border-slate-700">
                                    <span onClick={() => setLang('en')} className={`lang-pill-btn ${lang === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>EN</span>
                                    <span onClick={() => setLang('vi')} className={`lang-pill-btn ${lang === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>VI</span>
                                </div>
                            </div>

                            <div className="flex items-center gap-2 ml-auto">
                                <button 
                                    onClick={handleCopy} 
                                    disabled={isCopied}
                                    className={`p-2 rounded-xl transition-all hover:scale-110 active:scale-95 disabled:opacity-70 border shadow-sm ${isCopied ? 'text-emerald-600 border-emerald-200 bg-emerald-50 dark:bg-emerald-900/20' : 'bg-white dark:bg-slate-800 border-gray-200 dark:border-slate-700 text-slate-500 dark:text-slate-400 hover:text-indigo-600'}`}
                                    title={isCopied ? "Copied!" : "Copy to Clipboard"}
                                >
                                    <Icon name={isCopied ? "CheckThick" : "Copy"} size={16}/>
                                </button>
                            </div>
                        </div>

                        {/* Content Area */}
                        <div className="flex-1 p-5 overflow-y-auto custom-scrollbar bg-gray-50/50 dark:bg-slate-950/50 rounded-2xl border border-gray-100 dark:border-slate-800 relative shadow-inner text-left">
                            <div className="prose prose-sm md:prose-base dark:prose-invert max-w-none">
                                <p className="text-sm md:text-base text-slate-800 dark:text-slate-200 whitespace-pre-wrap leading-8 font-medium tracking-wide">
                                    {streamedText}
                                    {!isLoading && streamedText !== textToDisplay && (
                                        <span className="inline-block w-1.5 h-5 bg-indigo-500 animate-pulse ml-1 align-middle"></span>
                                    )}
                                </p>
                            </div>
                        </div>
                    </>
                )}
            </div>
        </Modal>
    );
};

export default ReferenceClauseModal;

import React, { useEffect, useState, useMemo, useImperativeHandle, forwardRef, useCallback, useRef } from 'react';
import { Icon } from '../UI';
import { Standard, MatrixRow, UploadedFile, Clause } from '../../types';
import { copyToClipboard } from '../../utils';
import { useStandardUtils } from '../../hooks/useStandardUtils';

export interface EvidenceMatrixHandle {
    insertEvidence: (clauseId: string, rowId: string, text: string) => void;
    handleExternalDictation: (text: string) => void;
    getActiveRow: () => { clauseId: string, rowId: string } | null;
}

interface EvidenceMatrixProps {
    standard: Standard;
    selectedClauses: string[];
    matrixData: Record<string, MatrixRow[]>;
    setMatrixData: React.Dispatch<React.SetStateAction<Record<string, MatrixRow[]>>>;
    onPasteFiles?: (files: File[], target: { clauseId: string, rowId: string }) => void;
    uploadedFiles?: UploadedFile[];
    onRemoveFile?: (fileId: string) => void;
    onLookup?: (clause: Clause) => void;
    onOcrProcess?: () => void;
    isProcessing?: boolean;
}

// --- MEMOIZED ROW COMPONENT ---
const MatrixRowItem = React.memo(({ 
    row, clauseId, clauseCode, 
    isActive, isDone, 
    onActivate, onRowChange, onPaste,
    textareaRef 
}: any) => {

    // --- LOCAL UNDO STATE ---
    const [showUndo, setShowUndo] = useState(false);
    const undoBufferRef = useRef<string>("");
    // Use ReturnType<typeof setTimeout> to handle both Node (NodeJS.Timeout) and Browser (number) environments compatible
    const undoTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

    // Internal handler to pass ID back
    const handleChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
        // If user starts typing while Undo is active, we assume they accept the clear state, so we dismiss undo
        if (showUndo) setShowUndo(false);
        onRowChange(clauseId, row.id, e.target.value);
    };

    const handleClear = () => {
        // 1. Snapshot current text
        undoBufferRef.current = row.evidenceInput;

        // 2. Clear text
        onRowChange(clauseId, row.id, "");

        // 3. Activate Undo mode for 5 seconds
        setShowUndo(true);
        if (undoTimerRef.current) clearTimeout(undoTimerRef.current);
        undoTimerRef.current = setTimeout(() => {
            setShowUndo(false);
        }, 5000);
    };

    const handleUndo = () => {
        // Restore from buffer
        onRowChange(clauseId, row.id, undoBufferRef.current);
        setShowUndo(false);
        if (undoTimerRef.current) clearTimeout(undoTimerRef.current);
    };

    const handlePasteWrapper = (e: React.ClipboardEvent) => {
        onPaste(e, clauseId, row.id);
    };

    return (
        <div 
            className={`flex flex-col h-full animate-in fade-in zoom-in-95 duration-200 ${isActive ? 'block' : 'hidden'}`}
        >
            {/* Requirement Context Header */}
            <div className="p-5 border-b border-gray-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-900/50 backdrop-blur-md sticky top-0 z-10">
                <div className="flex items-center justify-between gap-3 mb-3">
                    <div className="flex items-center gap-3">
                        <span className="text-xs font-black text-white bg-gradient-to-r from-indigo-500 to-purple-500 px-2 py-0.5 rounded shadow-sm">{clauseCode}</span>
                    </div>
                </div>
                <div className="bg-white dark:bg-slate-800 p-4 rounded-lg border-l-4 border-indigo-400 dark:border-indigo-600 shadow-sm">
                    {/* UPDATED FONT SIZE TO text-base (was text-xs) */}
                    <p className="text-base text-slate-700 dark:text-slate-200 leading-relaxed font-medium">
                        {row.requirement}
                    </p>
                </div>
            </div>

            {/* Large Editor Area */}
            <div className="flex-1 relative group bg-white dark:bg-slate-900">
                <textarea
                    ref={isActive ? textareaRef : null}
                    className="w-full h-full p-6 text-base text-slate-900 dark:text-white bg-transparent outline-none resize-none leading-7 placeholder-slate-300 dark:placeholder-slate-600 font-medium custom-scrollbar"
                    placeholder="Type verified evidence here... (Drag & Drop files supported)"
                    value={row.evidenceInput}
                    onChange={handleChange}
                    onPaste={handlePasteWrapper}
                    autoFocus
                />
            </div>

            {/* Footer Toolbar - Now holding the Actions */}
            <div className="px-4 py-2 border-t border-gray-100 dark:border-slate-800 flex items-center justify-between bg-gray-50/90 dark:bg-slate-950/90 backdrop-blur-sm transition-all min-h-[44px]">

                {/* Left: Stats */}
                <div className="text-[10px] text-slate-400 font-mono flex gap-3">
                    <span>Ln {row.evidenceInput.split('\n').length}</span>
                    <span>Col {row.evidenceInput.length}</span>
                </div>

                {/* Right: Actions & Status */}
                <div className="flex items-center gap-3">

                    {/* UNDO MODE */}
                    {showUndo ? (
                        <div className="flex items-center gap-2 bg-slate-200 dark:bg-slate-800 px-3 py-1 rounded-full animate-in slide-in-from-right-5 fade-in duration-300">
                            <span className="text-[10px] text-slate-500 font-medium">Cleared.</span>
                            <button 
                                onClick={handleUndo}
                                className="text-[10px] font-bold text-indigo-600 dark:text-indigo-400 hover:underline flex items-center gap-1"
                            >
                                <Icon name="Session5_RefreshCircle" size={12}/> Undo
                            </button>
                        </div>
                    ) : (
                        <>
                            {/* Saved Status */}
                            <div className={`flex items-center gap-1 transition-all duration-300 ${isDone ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-2 pointer-events-none'}`}>
                                <span className="w-1.5 h-1.5 rounded-full bg-emerald-500"></span>
                                <span className="text-[10px] font-bold text-emerald-600 dark:text-emerald-400 uppercase tracking-wider">Saved</span>
                            </div>

                            {/* Separator */}
                            <div className="h-4 w-px bg-slate-200 dark:bg-slate-700 mx-1"></div>

                            {/* Clear Button */}
                            <button 
                                onClick={handleClear}
                                className="flex items-center gap-1.5 px-3 py-1 rounded-lg text-slate-400 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 transition-all text-[10px] font-bold uppercase tracking-wide group/trash"
                                title="Clear Evidence"
                                disabled={!row.evidenceInput}
                            >
                                <Icon name="Trash2" size={14} className="group-hover/trash:scale-110 transition-transform"/>
                                <span>Clear</span>
                            </button>
                        </>
                    )}
                </div>
            </div>
        </div>
    );
});

// --- MAIN COMPONENT ---
export const EvidenceMatrix = forwardRef<EvidenceMatrixHandle, EvidenceMatrixProps>(({
    standard, selectedClauses, matrixData, setMatrixData, onPasteFiles, uploadedFiles = [], onRemoveFile, onLookup,
    onOcrProcess, isProcessing
}, ref) => {

    // Tracking active row
    const [activeRow, setActiveRow] = useState<{ clauseId: string, rowId: string } | null>(null);
    const [isChecklistCopied, setIsChecklistCopied] = useState(false);

    // Ref to access the DOM element of the active textarea
    const activeTextareaRef = useRef<HTMLTextAreaElement>(null);

    // Optimized utility hook
    const { getClauseById } = useStandardUtils(standard);

    // Initialization Logic
    useEffect(() => {
        setMatrixData(currentMatrix => {
            const newMatrix = { ...currentMatrix };
            let updated = false;
            let firstRowFound: { clauseId: string, rowId: string } | null = null;

            selectedClauses.forEach(clauseId => {
                // Initialize missing rows
                if (!newMatrix[clauseId] || newMatrix[clauseId].length === 0) {
                    const clause = getClauseById(clauseId);
                    if (clause) {
                        const desc = clause.description || "Requirement";
                        const reqs = desc.length > 300 
                            ? desc.split(/(?:\. |\n)/).filter(s => s.trim().length > 5) 
                            : [desc];

                        newMatrix[clauseId] = reqs.map((req, idx) => ({
                            id: `${clauseId}_req_${idx}`,
                            requirement: req.trim(),
                            evidenceInput: "",
                            status: 'pending'
                        }));
                        updated = true;
                    }
                }
                // Determine default active row if none
                if (!firstRowFound && newMatrix[clauseId] && newMatrix[clauseId].length > 0) {
                    firstRowFound = { clauseId, rowId: newMatrix[clauseId][0].id };
                }
            });

            if (!activeRow && firstRowFound) {
                setActiveRow(firstRowFound);
            }

            return updated ? newMatrix : currentMatrix;
        });
    }, [selectedClauses, getClauseById, setMatrixData]); 

    // --- HANDLERS ---
    const updateRowData = useCallback((clauseId: string, rowId: string, textToAppend: string) => {
        setMatrixData(prev => ({
            ...prev,
            [clauseId]: prev[clauseId].map(row => {
                if (row.id === rowId) {
                    const currentText = row.evidenceInput || "";
                    const separator = currentText && textToAppend ? "\n" : "";
                    const newText = currentText + separator + textToAppend;
                    return { ...row, evidenceInput: newText, status: newText.trim() ? 'supplied' : 'pending' };
                }
                return row;
            })
        }));
    }, [setMatrixData]);

    // OPTIMIZED: Direct state update for typing to avoid lag
    // This function MUST be stable to avoid re-rendering children
    const handleInputChange = useCallback((clauseId: string, rowId: string, value: string) => {
        setMatrixData(prev => {
            const currentRows = prev[clauseId];
            if (!currentRows) return prev;

            // Optimization: Only create new object if value actually changed
            const rowIndex = currentRows.findIndex(r => r.id === rowId);
            if (rowIndex === -1 || currentRows[rowIndex].evidenceInput === value) return prev;

            const newRows = [...currentRows];
            newRows[rowIndex] = { 
                ...newRows[rowIndex], 
                evidenceInput: value, 
                status: value.trim() ? 'supplied' : 'pending' 
            };

            return { ...prev, [clauseId]: newRows };
        });
    }, [setMatrixData]);

    const handlePaste = useCallback((e: React.ClipboardEvent, clauseId: string, rowId: string) => {
        const items = e.clipboardData.items;
        const files: File[] = [];
        for (let i = 0; i < items.length; i++) {
            if (items[i].kind === 'file') {
                const f = items[i].getAsFile();
                if (f) files.push(f);
            }
        }
        if (files.length > 0) {
            e.preventDefault();
            if (onPasteFiles) {
                onPasteFiles(files, { clauseId, rowId });
            }
        }
    }, [onPasteFiles]);

    // IMPERATIVE HANDLE
    useImperativeHandle(ref, () => ({
        insertEvidence: (clauseId, rowId, text) => {
            // FIX: Check if we are inserting into the currently focused/active textarea
            // If so, use cursor position. If not (e.g. inserting into a background row), just append.
            const isActive = activeRow?.clauseId === clauseId && activeRow?.rowId === rowId;

            if (isActive && activeTextareaRef.current) {
                const el = activeTextareaRef.current;
                const start = el.selectionStart;
                const end = el.selectionEnd;
                const oldText = el.value;

                // Insert at cursor
                const newText = oldText.substring(0, start) + text + oldText.substring(end);

                // Update State
                handleInputChange(clauseId, rowId, newText);

                // Try to restore cursor position after update (needs timeout for react render)
                setTimeout(() => {
                    if (activeTextareaRef.current) {
                        activeTextareaRef.current.focus();
                        const newCursorPos = start + text.length;
                        activeTextareaRef.current.setSelectionRange(newCursorPos, newCursorPos);
                    }
                }, 0);
            } else {
                // Fallback for background insertions
                updateRowData(clauseId, rowId, text);
            }
        },
        handleExternalDictation: (text) => { if (activeRow) updateRowData(activeRow.clauseId, activeRow.rowId, text); },
        getActiveRow: () => activeRow
    }));

    // --- DERIVED ACTIVE DATA ---
    const activeData = useMemo(() => {
        if (!activeRow) return null;
        const clause = getClauseById(activeRow.clauseId);
        const rows = matrixData[activeRow.clauseId];
        const row = rows?.find(r => r.id === activeRow.rowId);
        if (!clause || !row) return null;
        return { clause, row };
    }, [activeRow, matrixData, getClauseById]);

    const renderFilePreview = (fileEntry: UploadedFile) => {
        const isImage = fileEntry.file.type.startsWith('image/');
        const isPdf = fileEntry.file.type.includes('pdf');

        return (
            <div key={fileEntry.id} className="relative group w-20 h-20 bg-gray-50 dark:bg-slate-800 rounded-lg border border-gray-200 dark:border-slate-700 flex flex-col items-center justify-center overflow-hidden transition-all hover:shadow-md hover:-translate-y-1">
                {isImage ? (
                    <img src={URL.createObjectURL(fileEntry.file)} alt="preview" className="w-full h-full object-cover opacity-80 group-hover:opacity-100 transition-opacity" />
                ) : (
                    <div className="flex flex-col items-center p-2 text-center">
                        <Icon name={isPdf ? "BookOpen" : "FileText"} size={24} className="text-slate-400 mb-1"/>
                        <span className="text-[9px] text-slate-500 line-clamp-2 leading-tight break-all">{fileEntry.file.name}</span>
                    </div>
                )}

                <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors flex items-start justify-end p-1">
                    {fileEntry.status === 'processing' && (
                        <div className="absolute inset-0 bg-white/80 dark:bg-black/50 flex items-center justify-center">
                            <Icon name="Loader" size={16} className="animate-spin text-indigo-600"/>
                        </div>
                    )}
                    {fileEntry.status === 'success' && <div className="bg-emerald-500 rounded-full p-0.5 shadow-sm"><Icon name="CheckThick" size={10} className="text-white"/></div>}

                    <button 
                        onClick={(e) => { e.stopPropagation(); onRemoveFile && onRemoveFile(fileEntry.id); }}
                        className="bg-red-500 text-white rounded-full p-1 opacity-0 group-hover:opacity-100 transition-all hover:scale-110 shadow-sm"
                        title="Remove File"
                    >
                        <Icon name="X" size={10}/>
                    </button>
                </div>
            </div>
        );
    };

    if (selectedClauses.length === 0) {
        return (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 bg-gray-50/30 dark:bg-slate-900/30 rounded-3xl border-2 border-dashed border-gray-200 dark:border-slate-800 m-4">
                <div className="p-6 bg-white dark:bg-slate-900 rounded-full shadow-depth mb-4">
                    <Icon name="LayoutList" size={48} className="text-indigo-200 dark:text-slate-700"/>
                </div>
                <p className="text-sm font-bold text-slate-500">Select clauses to start mapping evidence.</p>
            </div>
        );
    }

    return (
        <div className="h-full flex flex-col relative animate-fade-in-up">
            {/* CONTENT AREA */}
            <div className="flex-1 min-h-0 bg-white dark:bg-slate-900 rounded-2xl border border-white/60 dark:border-slate-800 shadow-depth overflow-hidden flex">

                {/* LIST COLUMN */}
                <div className="w-1/3 min-w-[260px] max-w-[350px] border-r border-gray-100 dark:border-slate-800 flex flex-col bg-slate-50/50 dark:bg-slate-950/30 backdrop-blur-sm">
                    <div className="p-3 border-b border-gray-100 dark:border-slate-800 flex justify-between items-center bg-white/50 dark:bg-slate-900/50">
                        {/* UPDATE: Increased size from text-[10px] to text-xs */}
                        <span className="text-xs font-black text-slate-400 uppercase tracking-widest">Requirement Checklist</span>
                        <button 
                            onClick={() => { 
                                const list = selectedClauses.map(cid => {
                                    const c = getClauseById(cid);
                                    return c ? `[${c.code}] ${c.title}` : null;
                                }).filter(Boolean).join('\n');
                                if(list) {
                                    copyToClipboard(list);
                                    setIsChecklistCopied(true);
                                    setTimeout(() => setIsChecklistCopied(false), 2000);
                                }
                            }}
                            className={`text-xs font-bold flex items-center gap-1 transition-all duration-300 ${isChecklistCopied ? 'text-emerald-500 scale-105' : 'text-indigo-500 hover:text-indigo-600'}`}
                        >
                            <Icon name={isChecklistCopied ? "CheckThick" : "Copy"} size={12}/> 
                            {isChecklistCopied ? "Copied" : "Copy All"}
                        </button>
                    </div>
                    <div className="flex-1 overflow-y-auto custom-scrollbar p-2 space-y-4">
                        {selectedClauses.map(clauseId => {
                            const clause = getClauseById(clauseId);
                            const rows = matrixData[clauseId] || [];
                            if(!clause) return null;

                            return (
                                <div key={clauseId} className="space-y-1">
                                    <div className="flex items-center justify-between gap-2 px-2 py-2 group/header rounded-lg hover:bg-white dark:hover:bg-slate-800 transition-colors">
                                        <div className="flex items-center gap-2 overflow-hidden">
                                            {/* UPDATE: Increased size */}
                                            <span className="text-xs font-black text-indigo-500 bg-indigo-50 dark:bg-indigo-900/20 px-1.5 py-0.5 rounded flex-shrink-0 border border-indigo-100 dark:border-indigo-800/50">{clause.code}</span>
                                            <span className="text-base font-bold text-slate-700 dark:text-slate-300 truncate" title={clause.title}>{clause.title}</span>
                                        </div>
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); onLookup && onLookup(clause); }}
                                            className="p-1 text-slate-400 hover:text-indigo-500 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 rounded opacity-0 group-hover/header:opacity-100 transition-all scale-90 hover:scale-100"
                                            title="Read Clause Content"
                                        >
                                            <Icon name="BookOpen" size={14}/>
                                        </button>
                                    </div>
                                    <div className="pl-2 space-y-1">
                                        {rows.map((row) => {
                                            const isActive = activeRow?.rowId === row.id;
                                            const isDone = row.status === 'supplied';
                                            return (
                                                <div 
                                                    key={row.id}
                                                    onClick={() => setActiveRow({ clauseId, rowId: row.id })}
                                                    className={`group relative p-3 rounded-xl cursor-pointer transition-all border ${isActive ? 'bg-white dark:bg-slate-800 border-indigo-200 dark:border-indigo-600 shadow-sm ring-1 ring-indigo-500/10' : 'bg-transparent border-transparent hover:bg-white dark:hover:bg-slate-800/50 hover:border-slate-200 dark:hover:border-slate-700'}`}
                                                >
                                                    <div className="flex items-start gap-2.5">
                                                        <div className={`mt-1.5 w-2.5 h-2.5 rounded-full shrink-0 transition-all shadow-sm ${isDone ? 'bg-emerald-500 scale-110' : isActive ? 'bg-indigo-500 scale-110' : 'bg-slate-200 dark:bg-slate-700'}`}></div>
                                                        {/* UPDATE: Increased size from text-[11px] to text-sm */}
                                                        <p className={`text-sm leading-relaxed line-clamp-3 ${isActive ? 'text-slate-800 dark:text-slate-100 font-medium' : 'text-slate-500 dark:text-slate-400'}`}>
                                                            {row.requirement}
                                                        </p>
                                                    </div>
                                                </div>
                                            );
                                        })}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>

                {/* EDITOR COLUMN */}
                <div className="flex-1 flex flex-col bg-white dark:bg-slate-900 min-w-0 relative">
                    {activeData ? (
                        <div className="flex flex-col h-full animate-in fade-in zoom-in-95 duration-200">
                            {/* MatrixRowItem handles the editor rendering and logic efficiently */}
                            <MatrixRowItem 
                                key={activeData.row.id} // Important: re-mount on row change
                                row={activeData.row}
                                clauseId={activeData.clause.id}
                                clauseCode={activeData.clause.code}
                                isActive={true}
                                isDone={activeData.row.status === 'supplied'}
                                onRowChange={handleInputChange} // Pass stable callback
                                onPaste={handlePaste}
                                textareaRef={activeTextareaRef} // PASS THE REF
                            />

                            {/* FILES GRID - Always at bottom if present */}
                            {uploadedFiles.length > 0 && (
                                <div className="px-6 pt-4 pb-2 bg-slate-50/30 dark:bg-black/10 border-t border-gray-100 dark:border-slate-800">
                                    <div className="flex flex-wrap gap-3 items-center">
                                        {uploadedFiles.map(renderFilePreview)}

                                        {/* PROCESS BUTTON IN MATRIX */}
                                        <button
                                            onClick={(e) => { e.stopPropagation(); onOcrProcess && onOcrProcess(); }}
                                            disabled={isProcessing}
                                            className="group relative w-20 h-20 flex flex-col items-center justify-center gap-1 rounded-xl btn-shrimp text-white shadow-lg transition-all active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed hover:shadow-indigo-500/40"
                                            title="Process OCR for these files"
                                        >
                                            {isProcessing ? (
                                                <Icon name="Loader" size={24} className="animate-spin text-white"/>
                                            ) : (
                                                <Icon name="ScanText" size={24} className="group-hover:scale-110 transition-transform text-white"/>
                                            )}
                                            <span className="text-[9px] font-black uppercase tracking-wider text-white">OCR Process</span>
                                        </button>
                                    </div>
                                </div>
                            )}
                        </div>
                    ) : (
                        <div className="flex-1 flex flex-col items-center justify-center text-slate-300 dark:text-slate-600">
                            <Icon name="ArrowLeft" size={32} className="mb-2 opacity-50"/>
                            <p className="text-sm">Select a requirement from the checklist</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
});
